// Parser la réponse Gemini et préparer les données
const FACTURES_ROOT = '1AMLGJVhCzU0dJBtzVBx-2gpZrxuiF7rB';
const FACTURES_2026 = '1VfwFurXDhOoQEPzRezGTlQOR3s84XmCE';
const INBOX_FOLDER = '1q7o8oe07UvhqwNm1VKjhK0Vht832P3Pg';

const geminiResponse = $input.first().json;
const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';

const jsonMatch = text.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('Gemini n\'a pas retourné de JSON valide: ' + text.substring(0, 300));

const inv = JSON.parse(jsonMatch[0]);

// Vérifier HT + TVA = TTC
const diff = Math.abs((inv.montant_ht + inv.tva) - inv.montant_ttc);
if (diff > 0.05) throw new Error('Erreur comptable: HT(' + inv.montant_ht + ') + TVA(' + inv.tva + ') != TTC(' + inv.montant_ttc + ')');

// Nom fichier standardisé
// Gemini renvoie parfois "description" en tableau d'articles (au lieu d'une string) : on gère les deux cas
const descText = Array.isArray(inv.description)
  ? inv.description.map(item => item.article).filter(Boolean).join(', ')
  : String(inv.description || '');
const desc = descText.substring(0, 50).replace(/[^a-zA-Z0-9àâéèêëïîôùûç -]/g, '').trim().replace(/ /g, '-');
const driveFileName = inv.date + '_' + inv.fournisseur.replace(/ /g, '-') + '_' + inv.montant_ttc.toFixed(2) + 'EUR_' + desc;

// Dossier destination
const year = inv.date.split('-')[0];
const month = parseInt(inv.date.split('-')[1]);
const monthNames = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
const monthFolder = month.toString().padStart(2, '0') + ' — ' + monthNames[month - 1];
const yearFolderId = year === '2026' ? FACTURES_2026 : FACTURES_ROOT;

// Préparer la query de recherche du dossier mois
const searchQuery = "name='" + monthFolder + "' and '" + yearFolderId + "' in parents and mimeType='application/vnd.google-apps.folder' and trashed=false";

// Garder le fileId original pour le move
const originalFileId = $('Extraire base64').first().json.originalFileId;

return [{
  json: {
    ...inv,
    originalFileId,
    driveFileName,
    monthFolder,
    year,
    yearFolderId,
    searchQuery,
    inboxFolder: INBOX_FOLDER
  }
}];
